import{_ as e,o as t,c as o,O as a}from"./chunks/framework.bdcb0ee1.js";const _=JSON.parse('{"title":"Polls","description":"","frontmatter":{},"headers":[],"relativePath":"userguide/polls.md","filePath":"userguide/polls.md","lastUpdated":1773167498000}'),l={name:"userguide/polls.md"},n=a('<h1 id="polls" tabindex="-1">Polls <a class="header-anchor" href="#polls" aria-label="Permalink to &quot;Polls&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#creating-a-poll">Creating a poll</a></li><li><a href="#voting">Voting</a></li><li><a href="#viewing-results">Viewing results</a></li></ul></nav><h2 id="creating-a-poll" tabindex="-1">Creating a poll <a class="header-anchor" href="#creating-a-poll" aria-label="Permalink to &quot;Creating a poll&quot;">​</a></h2><p>When creating a new topic, you can attach a poll by expanding the poll section. Provide the following:</p><ul><li><strong>Question</strong> — the poll question (up to 255 characters).</li><li><strong>Options</strong> — add at least two options for members to vote on.</li><li><strong>View Results Without Voting</strong> — optionally allow members to see the results before casting their vote.</li></ul><p>Each topic can have one poll. Only the topic creator, moderators and administrators can add or remove polls.</p><h2 id="voting" tabindex="-1">Voting <a class="header-anchor" href="#voting" aria-label="Permalink to &quot;Voting&quot;">​</a></h2><p>To vote in a poll, select your preferred option and click <strong>Vote</strong>. You can only vote once per poll, and your vote cannot be changed after it is submitted.</p><p>If the poll creator enabled <strong>View Results Without Voting</strong>, you can see the current results before casting your vote by clicking <strong>View Results</strong>.</p><h2 id="viewing-results" tabindex="-1">Viewing results <a class="header-anchor" href="#viewing-results" aria-label="Permalink to &quot;Viewing results&quot;">​</a></h2><p>After voting, you will see the current results showing each option&#39;s vote count and percentage. If you have not voted and the poll does not allow viewing results first, the options will be displayed without counts.</p>',11),i=[n];function s(r,c,p,u,h,d){return t(),o("div",null,i)}const f=e(l,[["render",s]]);export{_ as __pageData,f as default};
